const { Router } = require('./router');
const { errorCatcher } = require('./middleware/error');

async function createApp(config) {
  const router = new Router();
  const middlewareStack = [];

  // Core middleware (order matters)
  middlewareStack.push(parseBody);
  middlewareStack.push(authenticate);
  middlewareStack.push(rateLimiter(config.rateLimit));
  middlewareStack.push(compressResponse);

  // Route handlers
  router.get('/api/users', listUsers);
  router.post('/api/users', createUser);
  router.get('/api/products', listProducts);
  router.put('/api/products/:id', updateProduct);

  async function dispatch(req, res) {
    let index = 0;
    async function next(err) {
      if (err) return onError(err, req, res);
      const mw = middlewareStack[index++];
      if (!mw) return router.handle(req, res);
      return mw(req, res, next);
    }
    await next();
  }

  async function onError(err, req, res) {
    const status = err.status || 500;
    res.status(status).json({ error: err.message });
  }

  return {
    use(mw) { middlewareStack.push(mw); },
    handle: dispatch,
    listen(port) { /* start HTTP server */ }
  };
}

module.exports = { createApp };

class EventStore {
  constructor() {
    this.streams = new Map();
    this.subscribers = new Map();
    this.version = 0;
  }

  appendStream(streamId, events) {
    if (!this.streams.has(streamId)) {
      this.streams.set(streamId, []);
    }
    const stream = this.streams.get(streamId);
    const expectedVersion = stream.length;
    events.forEach((event, i) => {
      event.id = ++this.version;
      event.streamVersion = expectedVersion + i;
      stream.push(event);
    });
    this._notifySubscribers(streamId, events);
  }

  loadStream(streamId) {
    return this.streams.get(streamId) ?? [];
  }

  subscribe(streamId, callback) {
    if (!this.subscribers.has(streamId)) {
      this.subscribers.set(streamId, new Set());
    }
    this.subscribers.get(streamId).add(callback);
  }

  _notifySubscribers(streamId, events) {
    const subs = this.subscribers.get(streamId);
    subs?.forEach(cb => cb(events));
  }
}

class AggregateRoot {
  constructor(id) {
    this.id = id;
    this.events = [];
  }

  apply(event) {
    this.events.push(event);
    this._applyEvent(event);
  }

  commit() {
    const committed = [...this.events];
    this.events = [];
    return committed;
  }
}

class UserRepository {
  constructor(dbClient) {
    this.db = dbClient;
    this.collection = 'users';
  }

  async findById(id) {
    return this.db.findOne(this.collection, { _id: id });
  }

  async findByEmail(email) {
    return this.db.findOne(this.collection, { email });
  }

  async findAll(filters = {}, options = {}) {
    const query = this._buildQuery(filters);
    const page = options.page ?? 1;
    const limit = options.limit ?? 20;
    const skip = (page - 1) * limit;
    const [results, total] = await Promise.all([
      this.db.find(this.collection, query).skip(skip).limit(limit),
      this.db.count(this.collection, query)
    ]);
    return { results, pagination: { page, limit, total } };
  }

  async save(user) {
    if (user._id) {
      return this.db.updateOne(this.collection, { _id: user._id }, user);
    }
    const result = await this.db.insertOne(this.collection, user);
    return { ...user, _id: result.insertedId };
  }

  async delete(id) {
    return this.db.deleteOne(this.collection, { _id: id });
  }

  _buildQuery(filters) {
    const query = {};
    if (filters.name) query.name = { $regex: filters.name, $options: 'i' };
    if (filters.role) query.role = filters.role;
    if (filters.createdAtFrom) query.createdAt = { $gte: filters.createdAtFrom };
    return query;
  }
}

module.exports = UserRepository;

class Container {
  constructor() {
    this.registrations = new Map();
    this.instances = new Map();
  }

  register(serviceKey, factory, scope = 'singleton') {
    this.registrations.set(serviceKey, { factory, scope });
    return this;
  }

  resolve(serviceKey) {
    if (this.instances.has(serviceKey)) {
      return this.instances.get(serviceKey);
    }
    const reg = this.registrations.get(serviceKey);
    if (!reg) throw new Error(`No registration for ${serviceKey}`);

    const dependencies = this._resolveDependencies(reg.factory);
    const instance = reg.factory(...dependencies);

    if (reg.scope === 'singleton') {
      this.instances.set(serviceKey, instance);
    }
    return instance;
  }

  _resolveDependencies(factory) {
    const paramNames = this._getParamNames(factory);
    return paramNames.map(name => this.resolve(name));
  }

  _getParamNames(factory) {
    const fnStr = factory.toString();
    const match = fnStr.match(/\(([^)]*)\)/);
    if (!match) return [];
    return match[1].split(',').map(s => s.trim()).filter(Boolean);
  }

  createChild() {
    const child = new Container();
    child.registrations = new Map(this.registrations);
    return child;
  }
}

module.exports = Container;

class MessageBus {
  constructor() {
    this.handlers = new Map();
    this.queue = [];
    this.processing = false;
  }

  subscribe(topic, handler) {
    if (!this.handlers.has(topic)) {
      this.handlers.set(topic, []);
    }
    this.handlers.get(topic).push(handler);
  }

  publish(topic, payload, options = {}) {
    const message = {
      topic,
      payload,
      timestamp: Date.now(),
      messageId: crypto.randomUUID(),
      retryCount: 0,
      ttl: options.ttl ?? 60000
    };

    const syncHandlers = this.handlers.get(topic);
    if (syncHandlers) {
      syncHandlers.forEach(h => h(message));
    }

    if (options.persist) {
      this.queue.push(message);
      this._drainQueue();
    }
  }

  async _drainQueue() {
    if (this.processing) return;
    this.processing = true;
    while (this.queue.length > 0) {
      const msg = this.queue.shift();
      try {
        await this._deliver(msg);
      } catch (err) {
        if (msg.retryCount < 3) {
          msg.retryCount++;
          this.queue.unshift(msg);
        }
      }
    }
    this.processing = false;
  }
}

module.exports = MessageBus;

class PluginEngine {
  constructor(app) {
    this.app = app;
    this.plugins = new Map();
    this.hooks = {
      beforeRequest: [],
      afterResponse: [],
      onError: [],
      onShutdown: []
    };
  }

  register(name, plugin) {
    if (this.plugins.has(name)) {
      throw new Error(`Plugin ${name} already registered`);
    }
    this.plugins.set(name, plugin);
    if (plugin.hooks) {
      Object.entries(plugin.hooks).forEach(([hookName, handlers]) => {
        if (Array.isArray(handlers)) {
          this.hooks[hookName].push(...handlers);
        }
      });
    }
    if (plugin.init) plugin.init(this.app);
  }

  async executeHook(hookName, context) {
    const handlers = this.hooks[hookName] ?? [];
    for (const handler of handlers) {
      await handler(context, () => handlers);
    }
    return context;
  }

  unregister(name) {
    this.plugins.delete(name);
  }

  listPlugins() {
    return Array.from(this.plugins.keys());
  }
}

module.exports = PluginEngine;

class CircuitBreaker {
  constructor(options = {}) {
    this.failureThreshold = options.failureThreshold ?? 5;
    this.recoveryTimeout = options.recoveryTimeout ?? 30000;
    this.monitorWindow = options.monitorWindow ?? 60000;
    this.state = 'closed';
    this.failureCount = 0;
    this.lastFailureTime = null;
    this.windowStart = Date.now();
    this.successCount = 0;
  }

  async execute(fn, ...args) {
    if (this.state === 'open') {
      if (Date.now() - this.lastFailureTime >= this.recoveryTimeout) {
        this._transitionTo('half-open');
      } else {
        throw new CircuitOpenError('Circuit is open');
      }
    }

    try {
      const result = await fn(...args);
      this._onSuccess();
      return result;
    } catch (error) {
      this._onFailure();
      throw error;
    }
  }

  _onSuccess() {
    if (this.state === 'half-open') {
      this.successCount++;
      if (this.successCount >= 3) {
        this._transitionTo('closed');
      }
    } else {
      this.failureCount = 0;
    }
  }

  _onFailure() {
    this.failureCount++;
    this.lastFailureTime = Date.now();
    if (this.failureCount >= this.failureThreshold) {
      this._transitionTo('open');
    }
  }

  _transitionTo(newState) {
    console.log(`Circuit breaker: ${this.state} -> ${newState}`);
    this.state = newState;
    if (newState === 'closed') {
      this.failureCount = 0;
      this.successCount = 0;
      this.windowStart = Date.now();
    }
  }
}

class CircuitOpenError extends Error {
  constructor(message) { super(message); this.name = 'CircuitOpenError'; }
}

module.exports = { CircuitBreaker, CircuitOpenError };

class CacheLayer {
  constructor(options = {}) {
    this.ttl = options.ttl ?? 3600;
    this.maxSize = options.maxSize ?? 1000;
    this.l1 = new Map(); // in-memory
    this.l2 = options.l2Store; // Redis/external
    this.misses = 0;
  }

  async get(key) {
    // L1: Check in-memory cache first
    if (this.l1.has(key)) {
      const entry = this.l1.get(key);
      if (entry.expiresAt > Date.now()) {
        this.l1.set(key, { ...entry, expiresAt: Date.now() + this.ttl * 1000 });
        return entry.value;
      }
      this.l1.delete(key);
    }

    // L2: Fall through to external store
    try {
      const value = await this.l2.get(key);
      if (value !== undefined && value !== null) {
        this._setL1(key, value);
        return JSON.parse(value);
      }
    } catch (err) {
      console.warn('L2 cache miss:', err.message);
    }

    this.misses++;
    return null;
  }

  async set(key, value, ttl) {
    this._setL1(key, value);
    try {
      await this.l2.set(key, JSON.stringify(value), ttl ?? this.ttl);
    } catch (err) {
      console.warn('L2 cache set failed:', err.message);
    }
  }

  _setL1(key, value) {
    if (this.l1.size >= this.maxSize) {
      const oldest = this.l1.keys().next().value;
      this.l1.delete(oldest);
    }
    this.l1.set(key, { value, expiresAt: Date.now() + this.ttl * 1000 });
  }
}

module.exports = CacheLayer;
